def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for x in range(7, 0, -1):
                for y in range(1, x + 4):
                    exp_part = np.exp((ratio - x) / (y + 0.5)) - 1
                    trig_part = np.tanh(ratio * y / (x + 0.1))
                    priority += (exp_part ** 3) * trig_part / (x * y + 1)
            priority += (np.sin(ratio * 2) + np.cos(ratio * 1.3)) ** 2.1
        elif 4 < ratio <= 7:
            sum1 = 0
            for p in range(1, int(np.ceil(ratio)) + 4):
                inner_sum = 0
                for q in range(1, p + 3):
                    denom = np.log1p(q + ratio) + 0.7
                    inner_sum += ((ratio - p) ** 2) * np.sin(ratio * q) / denom
                sum1 += np.tanh(inner_sum) * (p + 0.5)
            priority = sum1 + np.sqrt(ratio) * 15 - np.tanh(ratio - 4) * 3.5
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 14):
                term = ((ratio - 2) ** r) / ((r ** 1.1) * 2.1)
                s += term * np.cos(r * ratio * 0.9) * np.sin(r * np.sqrt(ratio))
            priority = s * np.cos(8 * ratio) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2.1
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.sin(n * ratio * 3)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.3 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 16):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 1.6) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 13):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5.5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.95)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7.2
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i * int(item * 2.5)) % 7 == 0:
            priority += np.log1p(i + bin_cap) * 2.3
        else:
            priority -= np.sqrt(i + bin_cap + 1) * 1.7
        priorities[i] = priority
    return priorities
